        return query.WhereIf(!string.IsNullOrWhiteSpace(filterText), e => e.Title!.Contains(filterText!) || e.Slug!.Contains(filterText!) || e.Summary!.Contains(filterText!) || e.Content!.Contains(filterText!) || e.ThumbnailUrl!.Contains(filterText!) || e.CoverImageUrl!.Contains(filterText!) || e.AuthorName!.Contains(filterText!) || e.Source!.Contains(filterText!) || e.SourceUrl!.Contains(filterText!) || e.SeoTitle!.Contains(filterText!) || e.SeoDescription!.Contains(filterText!) || e.SeoKeywords!.Contains(filterText!)).WhereIf(!string.IsNullOrWhiteSpace(title), e => e.Title.Contains(title)).WhereIf(!string.IsNullOrWhiteSpace(slug), e => e.Slug.Contains(slug)).WhereIf(!string.IsNullOrWhiteSpace(summary), e => e.Summary.Contains(summary)).WhereIf(!string.IsNullOrWhiteSpace(content), e => e.Content.Contains(content)).WhereIf(!string.IsNullOrWhiteSpace(thumbnailUrl), e => e.ThumbnailUrl.Contains(thumbnailUrl)).WhereIf(!string.IsNullOrWhiteSpace(coverImageUrl), e => e.CoverImageUrl.Contains(coverImageUrl)).WhereIf(type.HasValue, e => e.Type == type).WhereIf(!string.IsNullOrWhiteSpace(authorName), e => e.AuthorName.Contains(authorName)).WhereIf(!string.IsNullOrWhiteSpace(source), e => e.Source.Contains(source)).WhereIf(!string.IsNullOrWhiteSpace(sourceUrl), e => e.SourceUrl.Contains(sourceUrl)).WhereIf(status.HasValue, e => e.Status == status).WhereIf(publishedAtMin.HasValue, e => e.PublishedAt >= publishedAtMin!.Value).WhereIf(publishedAtMax.HasValue, e => e.PublishedAt <= publishedAtMax!.Value).WhereIf(isFeatured.HasValue, e => e.IsFeatured == isFeatured).WhereIf(isHot.HasValue, e => e.IsHot == isHot).WhereIf(isTrending.HasValue, e => e.IsTrending == isTrending).WhereIf(viewCountMin.HasValue, e => e.ViewCount >= viewCountMin!.Value).WhereIf(viewCountMax.HasValue, e => e.ViewCount <= viewCountMax!.Value).WhereIf(likeCountMin.HasValue, e => e.LikeCount >= likeCountMin!.Value).WhereIf(likeCountMax.HasValue, e => e.LikeCount <= likeCountMax!.Value).WhereIf(shareCountMin.HasValue, e => e.ShareCount >= shareCountMin!.Value).WhereIf(shareCountMax.HasValue, e => e.ShareCount <= shareCountMax!.Value).WhereIf(commentCountMin.HasValue, e => e.CommentCount >= commentCountMin!.Value).WhereIf(commentCountMax.HasValue, e => e.CommentCount <= commentCountMax!.Value).WhereIf(readingTimeMin.HasValue, e => e.ReadingTime >= readingTimeMin!.Value).WhereIf(readingTimeMax.HasValue, e => e.ReadingTime <= readingTimeMax!.Value).WhereIf(!string.IsNullOrWhiteSpace(seoTitle), e => e.SeoTitle.Contains(seoTitle)).WhereIf(!string.IsNullOrWhiteSpace(seoDescription), e => e.SeoDescription.Contains(seoDescription)).WhereIf(!string.IsNullOrWhiteSpace(seoKeywords), e => e.SeoKeywords.Contains(seoKeywords));
